var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":" 그거 듣던 중 좋은 소식이네요.","JPN":" それは良い知らせですね。","ENG":"That's one good news.","TWN":"這可真是個好消息。"},"stage":{"bg":"THRONE","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":" 그렇다면 이제 결정을 내리셨다는 뜻으로 받아들여도 될까요?","JPN":" ということは、もう心を決めたと考えていいんでしょうか？","ENG":"Would it be safe for me to assume that you are determined with your decision?","TWN":"那現在我能理解成你已經做出決定了嗎？"},"stage":{"bg":"THRONE","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SAVIOR_KNIGHT_NULL_NULL","text":{"KOREA":" 네. 각오는 마쳤습니다.","JPN":" はい、覚悟はできています。","ENG":"Yes. I am prepared for whatever comes my way.","TWN":"是的，我做好心理準備了。"},"stage":{"bg":"THRONE","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAVIOR_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":" 레이 선배……. 분위기가 달라졌어.","JPN":" レイ先輩……雰囲気が違う。","ENG":"Ray... He looks different now.","TWN":"雷伊前輩……感覺變得不一樣了。"},"stage":{"bg":"THRONE","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":" 조심하시는 편이 좋겠어요, 미나 양.","JPN":" 気をつけた方が良さそうですね、ミナさん。","ENG":"You better be careful, Mina.","TWN":"最好小心點，米娜。"},"stage":{"bg":"THRONE","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":" 기백……. 이라고 해야 할까요.","JPN":" 気迫……と言いますか。","ENG":"His aura... should I say?","TWN":"該說是……氣勢嗎？"},"stage":{"bg":"THRONE","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":" 허신, 아니. 황태자 전하도 저 분에게 비하기 어렵겠어요.","JPN":" 虚神、いや。皇太子殿下もあの方の比じゃありません。","ENG":"It's more than the Hollow God... or even the crown prince.","TWN":"幻神，不，就連皇太子殿下也很難比得上現在的他。"},"stage":{"bg":"THRONE","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":" ……우리가 늦었군. 네헤모트.","JPN":" ……我々が遅れたか。ネヘモト。","ENG":"...We're late, Nehemoth.","TWN":"看來我們還是晚了一步，貝赫莫特。"},"stage":{"bg":"THRONE","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SAVIOR_KNIGHT_NULL_NULL","text":{"KOREA":" 간발의 차이였다고 말씀드리겠습니다, 발키리.","JPN":" 間一髪といったところでしたよ。ヴァルキリー。","ENG":"I should only say that you were very close, Valkyrie.","TWN":"你們已經很接近成功了，女武神。"},"stage":{"bg":"THRONE","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAVIOR_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SAVIOR_KNIGHT_NULL_NULL","text":{"KOREA":" 대적자라는 동맹이 아니었다면 늦었다는 말은 제 쪽에서 하게 되었겠죠.","JPN":" 敵対者という同盟がいなかったら、遅れるのは僕の方になったでしょうね。","ENG":"If there has not been my alliance, the Antagonist, I would have said that I was late.","TWN":"要不是有與敵對者聯手，恐怕這句話會是由我來說吧。"},"stage":{"bg":"THRONE","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAVIOR_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SAVIOR_KNIGHT_NULL_NULL","text":{"KOREA":" 하지만…….","JPN":" でも……","ENG":"However...","TWN":"不過……"},"stage":{"bg":"THRONE","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAVIOR_KNIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SAVIOR_KNIGHT_NULL_NULL","text":{"KOREA":" 네. 여러분은 늦었습니다. 당신의 말대로.","JPN":" はい。皆さんは遅れました。あなたの言う通り。","ENG":"Yes. You are late, as you told me so.","TWN":"沒錯，你們來晚了，就像你說的那樣。"},"stage":{"bg":"THRONE","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAVIOR_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SAVIOR_KNIGHT_NULL_NULL","text":{"KOREA":" 유미나 님. 일전의 추태에 대해서는 사과드리고 싶습니다.","JPN":" ミナさん。この間の醜態は謝ります。","ENG":"Yoo Mina. I apologize for the disgraceful behavior earlier.","TWN":"劉米娜，對於幾天前的醜態，我想向你道歉。"},"stage":{"bg":"THRONE","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAVIOR_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SAVIOR_KNIGHT_NULL_NULL","text":{"KOREA":" 저는 당신이 넘어서야 하고, 쓰러뜨려야 할 상대.","JPN":" 僕はあなたが乗り越え、倒さなければならない相手。","ENG":"I am one you must defeat and surpass.","TWN":"我是你要超越，要打倒的對手。"},"stage":{"bg":"THRONE","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAVIOR_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SAVIOR_KNIGHT_NULL_NULL","text":{"KOREA":" 그 너머에 기다릴 시련들을 알고 있는 사람이라면 적어도 죽음을 구걸해선 안 됐습니다.","JPN":" その先に待っているあらゆる試練を知る者として、少なくとも死を乞うてはならなかったんです。","ENG":"I shouldn't have begged for death, as someone who knows what lies beyond.","TWN":"作為明知道前方有考驗等在那裡的人，至少不應該祈求死亡。"},"stage":{"bg":"THRONE","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAVIOR_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":" …….","JPN":" ……","ENG":"...","TWN":"……"},"stage":{"bg":"THRONE","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SAVIOR_KNIGHT_NULL_NULL","text":{"KOREA":" 저는 구원자로서도, 마왕으로서도 실패한 몸.","JPN":" 僕は救世主としても、魔王としても失敗した身。","ENG":"I have neither succeeded myself as a Savior, nor a Demon Lord.","TWN":"我作為救贖者和魔王都是失敗的。"},"stage":{"bg":"THRONE","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAVIOR_KNIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SAVIOR_KNIGHT_NULL_NULL","text":{"KOREA":" 믿음에 부응하지 못했고, 당신들의 시련이 되기에도 턱없이 부족하겠지만.","JPN":" 信頼に応えられず、あなたたちの試練となるにもまったく足りないと思いますが。","ENG":"I have failed to correspond to expectations from others and I am incapable of being your worst binding.","TWN":"辜負了同伴的信任，成為你們的考驗也還遠遠不足。"},"stage":{"bg":"THRONE","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAVIOR_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SAVIOR_KNIGHT_NULL_NULL","text":{"KOREA":" 동료들이 내게 선물해 준 마지막 생명을 불태우려 합니다.","JPN":" 仲間たちが僕にくれた最後の命を燃やしてみようと思います。","ENG":"Therefore, I intend to ignite every bit of the life that my dear friends have bestowed on me.","TWN":"但至少，我想燃燒這條同伴們賦予我的最後生命。"},"stage":{"bg":"THRONE","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAVIOR_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SAVIOR_KNIGHT_NULL_NULL","text":{"KOREA":" 다른 누군가가 아닌… 오직 나의 의지로!","JPN":" 他の誰かではない……僕自身の意志で！","ENG":"Not by anyone else... but my own will!","TWN":"不是為了任何人……只是為了我自己！這是我自己的意志！"},"stage":{"bg":"THRONE","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAVIOR_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};